+            if let Some(v) = args.first() {
+                Ok(SqliteValue::Text(
+                    match v {
+                        SqliteValue::Null => "null",
+                        SqliteValue::Integer(_) => "integer",
+                        SqliteValue::Float(_) => "real",
+                        SqliteValue::Text(_) => "text",
+                        SqliteValue::Blob(_) => "blob",
